final class SecureTokenStore {
    private let service = "com.tradingapp.securetoken"
    private let account = "apiToken"
    
    func save(token: String) throws {
        let data = Data(token.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        SecItemDelete(query as CFDictionary)
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        let status = SecItemAdd(attributes as CFDictionary, nil)
        guard status == errSecSuccess else { throw NSError(domain: NSOSStatusErrorDomain, code: Int(status)) }
    }
    
    func load() -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func delete() {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - API Client

final class TradingAPIClient {
    static let shared = TradingAPIClient()
    
    private let baseURL = URL(string: "https://api.yourbroker.com/v1")!
    private let session: URLSession
    private let tokenStore = SecureTokenStore()
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    
    private init(session: URLSession = .shared) {
        self.session = session
        self.decoder = JSONDecoder()
        self.encoder = JSONEncoder()
        decoder.dateDecodingStrategy = .iso8601
        encoder.dateEncodingStrategy = .iso8601
    }
    
    func setToken(_ token: String) throws {
        try tokenStore.save(token: token)
    }
    
    func clearToken() {
        tokenStore.delete()
    }
    
    private func request<T: Decodable>(_ path: String, method: String = "GET", body: Data? = nil) async throws -> T {
        var request = URLRequest(url: baseURL.appendingPathComponent(path))
        request.httpMethod = method
        request.httpBody = body
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        if let token = tokenStore.load() {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        let (data, response) = try await session.data(for: request)
        guard let http = response as? HTTPURLResponse else {
            throw URLError(.badServerResponse)
        }
        guard (200...299).contains(http.statusCode) else {
            if let apiError = try? decoder.decode(APIErrorResponse.self, from: data) {
                throw apiError
            }
            throw NSError(domain: "TradingAPI", code: http.statusCode, userInfo: [NSLocalizedDescriptionKey: "Request failed with status \(http.statusCode)"])
        }
        return try decoder.decode(T.self, from: data)
    }
    
    func fetchQuote(symbol: String) async throws -> StockQuote {
        try await request("quotes/\(symbol)")
    }
    
    func fetchPortfolio() async throws -> (account: TradingAccount, holdings: [Holding], orders: [TradeOrder]) {
        struct Payload: Codable {
            let account: TradingAccount
            let holdings: [Holding]
            let orders: [TradeOrder]
        }
        let payload: Payload = try await request("portfolio")
        return (payload.account, payload.holdings, payload.orders)
    }
    
    func submitTrade(_ requestModel: TradeRequest) async throws -> TradeResponse {
        let body = try encoder.encode(requestModel)
        return try await request("trades", method: "POST", body: body)
    }
    
    func fetchOrders() async throws -> [TradeOrder] {
        try await request("orders")
    }
    
    func searchSymbols(query: String) async throws -> [StockQuote] {
        let encoded = query.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? query
        return try await request("search?query=\(encoded)")
    }
}

