@MainActor
final class PortfolioViewModel: ObservableObject {
    @Published var account = TradingAccount(accountId: "—", currency: "USD", summary: PortfolioSummary(cashBalance: 0, totalMarketValue: 0, totalCostBasis: 0, totalEquity: 0, unrealizedPnL: 0, unrealizedPnLPercent: 0))
    @Published var holdings: [Holding] = []
    @Published var orders: [TradeOrder] = []
    @Published var quotes: [String: StockQuote] = [:]
    @Published var isLoading = false
    @Published var errorMessage: String?
    
    private let api = TradingAPIClient.shared
    private var refreshTask: Task<Void, Never>?
    
    func loadAll() async {
        isLoading = true
        errorMessage = nil
        do {
            let result = try await api.fetchPortfolio()
            account = result.account
            holdings = result.holdings
            orders = result.orders
            await refreshQuotes()
        } catch {
            errorMessage = error.localizedDescription
        }
        isLoading = false
    }
    
    func refreshQuotes() async {
        await withTaskGroup(of: (String, StockQuote)?.self) { group in
            for holding in holdings {
                group.addTask {
                    do {
                        let quote = try await self.api.fetchQuote(symbol: holding.symbol)
                        return (holding.symbol, quote)
                    } catch {
                        return nil
                    }
                }
            }
            for await result in group {
                if let (symbol, quote) = result {
                    quotes[symbol] = quote
                    if let index = holdings.firstIndex(where: { $0.symbol == symbol }) {
                        holdings[index].currentPrice = quote.price
                    }
                }
            }
        }
        recalculateSummary()
    }
    
    func placeOrder(symbol: String, side: TradeSide, type: OrderType, quantity: Int, limitPrice: Double?) async -> Bool {
        isLoading = true
        errorMessage = nil
        do {
            let response = try await api.submitTrade(.init(symbol: symbol, side: side, type: type, quantity: quantity, limitPrice: limitPrice))
            account.summary = response.summary
            holdings = response.updatedHoldings
            orders.insert(response.order, at: 0)
            isLoading = false
            return true
        } catch {
            errorMessage = error.localizedDescription
            isLoading = false
            return false
        }
    }
    
    func startAutoRefresh(interval: TimeInterval = 8) {
        refreshTask?.cancel()
        refreshTask = Task {
            while !Task.isCancelled {
                await refreshQuotes()
                try? await Task.sleep(nanoseconds: UInt64(interval * 1_000_000_000))
            }
        }
    }
    
    func stopAutoRefresh() {
        refreshTask?.cancel()
        refreshTask = nil
    }
    
    private func recalculateSummary() {
        let marketValue = holdings.reduce(0) { $0 + $1.marketValue }
        let costBasis = holdings.reduce(0) { $0 + $1.costBasis }
        let pnl = marketValue - costBasis
        account.summary.totalMarketValue = marketValue
        account.summary.totalCostBasis = costBasis
        account.summary.totalEquity = account.summary.cashBalance + marketValue
        account.summary.unrealizedPnL = pnl
        account.summary.unrealizedPnLPercent = costBasis == 0 ? 0 : (pnl / costBasis) * 100.0
    }
}

@MainActor
final class TradeTicketViewModel: ObservableObject {
    @Published var symbol: String = ""
    @Published var side: TradeSide = .buy
    @Published var type: OrderType = .market
    @Published var quantity: String = "1"
    @Published var limitPrice: String = ""
    @Published var isSubmitting = false
    @Published var resultMessage: String?
    
    private let portfolioVM: PortfolioViewModel
    
    init(portfolioVM: PortfolioViewModel) {
        self.portfolioVM = portfolioVM
    }
    
    var quantityValue: Int { Int(quantity) ?? 0 }
    var limitPriceValue: Double? {
        let trimmed = limitPrice.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? nil : Double(trimmed)
    }
    
    func submit() async {
        guard !symbol.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
            resultMessage = "Enter a symbol."
            return
        }
        guard quantityValue > 0 else {
            resultMessage = "Enter a valid quantity."
            return
        }
        if type == .limit, limitPriceValue == nil || (limitPriceValue ?? 0) <= 0 {
            resultMessage = "Enter a valid limit price."
            return
        }
        isSubmitting = true
        let ok = await portfolioVM.placeOrder(symbol: symbol.uppercased(), side: side, type: type, quantity: quantityValue, limitPrice: limitPriceValue)
        resultMessage = ok ? "Order submitted successfully." : (portfolioVM.errorMessage ?? "Order failed.")
        isSubmitting = false
    }
}

