                        }
                        .font(.caption)
                        .foregroundStyle(.secondary)
                        
                        if let price = order.executedPrice {
                            Text("Executed at \(price, format: .currency(code: "USD"))")
                                .font(.caption)
                        }
                        if let message = order.message {
                            Text(message)
                                .font(.caption2)
                                .foregroundStyle(.secondary)
                        }
                    }
                    .padding(.vertical, 4)
                }
            }
